import test from 'node:test';
import assert from 'node:assert/strict';
import { auditSchedule } from '../scheduler/audit.js';
import { defaultTimeSlots } from '../scheduler/time.js';
test('audit reports fixed and soft preference outcomes', () => { const data = { students: [], grades: [{ id: 'g1', name: 'G1', memberGradeIds: ['g1'], studentIds: [] }], cohorts: [{ id: 'c1', name: 'G1', gradeIds: ['g1'], studentIds: [] }], teachers: [{ id: 't1', name: 'T1', aliases: [], unavailableSlots: [], preferredSlots: [] }], subjects: [{ id: 'pe', name: 'PE', aliases: [] }], rooms: [], timeSlots: defaultTimeSlots(), warnings: [], errors: [], sourceSheets: [], diagnostics: { sheetRanges: {}, headers: [], gradeBlocks: [], teacherBlocks: [], skippedBlocks: [], detectedSubjectCount: 1, detectedRequirementCount: 1, allocationTeacherAliases: [], needsMapping: [] }, constraints: [{ id: 'fix', type: 'fixed-slot', targetRequirementIds: ['pe'], value: { day: '월', startPeriod: 5, originalText: 'G1 PE 월요일 5교시' }, hard: true, source: 'excel' }, { id: 'pm', type: 'preferred-period-range', targetRequirementIds: ['pe'], value: { periods: [5, 6, 7], originalText: 'G1 PE' }, hard: false, source: 'excel' }], requirements: [{ id: 'pe', subjectId: 'pe', gradeIds: ['g1'], cohortIds: ['c1'], teacherIds: ['t1'], totalPeriodsPerWeek: 1, meetingsPerWeek: 1, meetingLengths: [1], fixedSlots: ['월-5'], allowedSlots: [], forbiddenSlots: [], preferredSlots: ['월-5'], consecutive: false, afterSchool: false, sharedClass: false, eventType: 'normal-class', priority: 1 }] }; const result = { assignments: [{ instanceId: 'pe_1', slot: '월-5', length: 1, subjectId: 'pe', gradeIds: ['g1'], cohortIds: ['c1'], studentIds: [], teacherIds: ['t1'] }], unassigned: [], issues: [], score: 0, progress: { elapsedMs: 0, nodes: 1, backtracks: 0, assigned: 1, total: 1, unassigned: 0, assignedPeriods: 1, totalPeriods: 1, unassignedPeriods: 0, bestScore: 0, reason: 'complete' } }; const audit = auditSchedule(data, result); assert.equal(audit.summary.hardFailed, 0); assert.equal(audit.summary.softSatisfied, 1); assert(audit.items.some(i => i.ruleType === 'Fixed-slot rule' && i.passed)); });
